    $display("SWD_SEQ: start");

    // -----------------------------------------------------------------------
    // DBG-01: DAP connect — verify swdo/swdo_en responds to JTAG-to-SWD switch
    // Drive SWD dormant wakeup sequence (50 clocks high)
    // -----------------------------------------------------------------------
